from __future__ import annotations
from functools import total_ordering

@total_ordering           # derives all comparison methods from __eq__ + __lt__
class Money:
    def __init__(self, amount: float, currency: str = "USD"):
        self.amount = round(float(amount), 2)
        self.currency = currency.upper()

    # --- Representation ---
    def __repr__(self) -> str:
        return f"Money({self.amount!r}, {self.currency!r})"

    def __str__(self) -> str:
        return f"{self.currency} {self.amount:.2f}"

    # --- Equality and hashing (always define both together) ---
    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Money):
            return NotImplemented
        return self.amount == other.amount and self.currency == other.currency

    def __hash__(self) -> int:
        return hash((self.amount, self.currency))

    # --- Ordering (total_ordering fills in __gt__, __ge__, __le__) ---
    def __lt__(self, other: Money) -> bool:
        if not isinstance(other, Money):
            return NotImplemented
        if self.currency != other.currency:
            raise TypeError(f"Cannot compare {self.currency} and {other.currency}")
        return self.amount < other.amount

    # --- Arithmetic ---
    def __add__(self, other: Money) -> Money:
        if not isinstance(other, Money):
            return NotImplemented
        if self.currency != other.currency:
            raise TypeError(f"Cannot add {self.currency} and {other.currency}")
        return Money(self.amount + other.amount, self.currency)

    def __mul__(self, factor: float) -> Money:
        if not isinstance(factor, (int, float)):
            return NotImplemented
        return Money(self.amount * factor, self.currency)

    def __rmul__(self, factor: float) -> Money:   # factor * money
        return self.__mul__(factor)

    def __bool__(self) -> bool:
        return self.amount != 0

# Usage
price = Money(9.99)
tax   = Money(0.80)
print(price + tax)           # USD 10.79
print(1.1 * price)           # USD 10.99
print(sorted([tax, price]))  # [Money(0.8, 'USD'), Money(9.99, 'USD')]
print({price, tax})          # works — both are hashable

class TokenWindow:
    """Yields overlapping chunks of tokens with a configurable stride."""

    def __init__(self, tokens: list[str], size: int = 512, stride: int = 256):
        if size <= 0 or stride <= 0:
            raise ValueError("size and stride must be positive")
        self.tokens = tokens
        self.size   = size
        self.stride = stride
        self._pos   = 0

    def __iter__(self):
        self._pos = 0      # reset so the object is re-iterable
        return self

    def __next__(self) -> list[str]:
        if self._pos >= len(self.tokens):
            raise StopIteration
        chunk = self.tokens[self._pos : self._pos + self.size]
        self._pos += self.stride
        return chunk

    def __len__(self) -> int:
        import math
        if not self.tokens:
            return 0
        return math.ceil(len(self.tokens) / self.stride)

# Works with for, list(), sum(), any standard iterator consumer
tokens = ["tok"] * 1000
window = TokenWindow(tokens, size=512, stride=256)
chunks = list(window)
print(f"{len(chunks)} chunks, first chunk size: {len(chunks[0])}")
# Second iteration resets correctly
for chunk in window:
    print(f"chunk of {len(chunk)} tokens")
    break

from typing import Callable, Iterator
import json

class ToolRegistry:
    """
    A container for LLM-callable tools.
    Implements container, iterator, and callable protocols so it
    integrates with any framework expecting an iterable of tools.
    """

    def __init__(self):
        self._tools: dict[str, Callable] = {}
        self._schemas: dict[str, dict]   = {}

    def register(self, name: str, schema: dict):
        """Decorator factory."""
        def decorator(fn: Callable) -> Callable:
            self._tools[name] = fn
            self._schemas[name] = schema
            return fn
        return decorator

    # --- Container protocol ---
    def __len__(self)              -> int:      return len(self._tools)
    def __contains__(self, name)   -> bool:     return name in self._tools
    def __iter__(self)             -> Iterator: return iter(self._tools)
    def __getitem__(self, name)    -> Callable: return self._tools[name]

    # --- Callable protocol ---
    def __call__(self, name: str, **kwargs):
        if name not in self:
            raise KeyError(f"Unknown tool: {name!r}")
        return self._tools[name](**kwargs)

    # --- Representation ---
    def __repr__(self) -> str:
        return f"ToolRegistry({list(self._tools)!r})"

    def schemas(self) -> list[dict]:
        return list(self._schemas.values())


registry = ToolRegistry()

@registry.register("search", schema={"name": "search", "description": "Web search"})
def search(query: str) -> str:
    return f"results for {query}"

print(len(registry))          # 1
print("search" in registry)   # True
print(list(registry))         # ['search']
print(registry("search", query="dunder methods"))

# WRONG: raises instead of returning NotImplemented
class Vector:
    def __add__(self, other):
        if not isinstance(other, Vector):
            raise NotImplementedError("Can only add vectors")  # breaks __radd__ fallback
        ...

# RIGHT: return NotImplemented; let the interpreter handle fallback
class Vector:
    def __add__(self, other):
        if not isinstance(other, Vector):
            return NotImplemented   # triggers other.__radd__(self)
        return Vector(self.x + other.x, self.y + other.y)

class Point:
    def __init__(self, x, y):
        self.x, self.y = x, y

    def __eq__(self, other):
        return isinstance(other, Point) and self.x == other.x and self.y == other.y

    # Missing __hash__ — instances cannot go into sets or dicts!
    # Fix:
    def __hash__(self):
        return hash((self.x, self.y))   # must use only the fields that __eq__ uses

# WRONG: container returning self makes it single-use
class BadBuffer:
    def __iter__(self):
        self._pos = 0
        return self          # concurrent loops share state — broken

    def __next__(self):
        ...

# RIGHT: delegate to a separate iterator class
class GoodBuffer:
    def __iter__(self):
        return _BufferIterator(self)   # each loop gets its own cursor

class _BufferIterator:
    def __init__(self, buf):
        self._buf = buf
        self._pos = 0

    def __iter__(self): return self

    def __next__(self):
        if self._pos >= len(self._buf._data):
            raise StopIteration
        val = self._buf._data[self._pos]
        self._pos += 1
        return val
